    public void addProductColumn(String columnName, String columnType) {
        // Validate column name
        if (columnName == null || columnName.trim().isEmpty()) {
            throw new IllegalArgumentException("Column name cannot be null or blank");
        }
        if (!columnName.matches("^[a-zA-Z_][a-zA-Z0-9_]*$")) {
            throw new IllegalArgumentException(
                "Invalid column name: '" + columnName + 
                "'. Must start with a letter or underscore, followed by letters, numbers, or underscores."
            );
        }

        // Validate column type
        if (columnType == null || columnType.trim().isEmpty()) {
            throw new IllegalArgumentException("Column type cannot be null or blank");
        }
        String trimmedType = columnType.trim();
        if (trimmedType.contains(";") || trimmedType.contains("--")) {
            throw new IllegalArgumentException(
                "Invalid column type: '" + columnType + 
                "'. Contains forbidden characters (semicolon or double hyphen)."
            );
        }

        // Construct and execute SQL statement
        String sql = String.format("ALTER TABLE products ADD COLUMN %s %s;", columnName, trimmedType);
        try {
            jdbcTemplate.execute(sql);
        } catch (DataAccessException e) {
            throw new RuntimeException(
                "Failed to add column '" + columnName + "' with type '" + trimmedType + "' to products table", 
                e
            );
        }
    }
}
